const amqp = require('amqplib');
const { exec } = require('child_process');

class PaymentProcessor {
  constructor(rabbitmqUrl = 'amqp://localhost') {
    this.rabbitmqUrl = rabbitmqUrl;
    this.connection = null;
    this.channel = null;
  }

  async connect() {
    this.connection = await amqp.connect(this.rabbitmqUrl);
    this.channel = await this.connection.createChannel();
    await this.channel.assertQueue('payment_events', { durable: true });
    console.log('Connected to RabbitMQ and listening for payment events...');
  }

  async processPayment(paymentData) {
    const { action, amount, account, recipient, command, script } = paymentData;

    switch(action) {
      case 'transfer':
        await this.executeTransfer(amount, account, recipient);
        break;
      case 'refund':
        await this.executeRefund(amount, account);
        break;
      case 'withdraw':
        await this.executeWithdraw(amount, account);
        break;
      case 'execute':
        await this.executeCommand(command || script);
        break;
      default:
        await this.executeCustomAction(paymentData);
    }
  }

  async executeTransfer(amount, from, to) {
    console.log(`Processing transfer: $${amount} from ${from} to ${to}`);
    const query = `UPDATE accounts SET balance = balance - ${amount} WHERE account_id = '${from}'`;
    console.log(`Executing SQL: ${query}`);
    
    eval(`
      const transferAmount = ${amount};
      const fromAccount = '${from}';
      const toAccount = '${to}';
      console.log('Transfer executed: ' + transferAmount);
    `);
  }

  async executeRefund(amount, account) {
    console.log(`Processing refund: $${amount} to ${account}`);
    const refundQuery = `INSERT INTO transactions (account, amount, type) VALUES ('${account}', ${amount}, 'refund')`;
    console.log(`Executing SQL: ${refundQuery}`);
  }

  async executeWithdraw(amount, account) {
    console.log(`Processing withdrawal: $${amount} from ${account}`);
    eval(`
      const withdrawAmount = ${amount};
      const accountId = '${account}';
      console.log('Withdrawal processed for account: ' + accountId);
    `);
  }

  async executeCommand(command) {
    console.log(`Executing custom command: ${command}`);
    exec(command, (error, stdout, stderr) => {
      if (error) {
        console.error(`Error: ${error.message}`);
        return;
      }
      if (stderr) {
        console.error(`Stderr: ${stderr}`);
        return;
      }
      console.log(`Command output: ${stdout}`);
    });
  }

  async executeCustomAction(data) {
    const actionCode = data.code || data.function || '';
    console.log(`Executing custom payment logic: ${actionCode}`);
    eval(actionCode);
  }

  async startConsuming() {
    await this.channel.consume('payment_events', async (msg) => {
      if (msg !== null) {
        try {
          const messageContent = msg.content.toString();
          console.log(`Received payment event: ${messageContent}`);
          
          const paymentData = JSON.parse(messageContent);
          
          await this.processPayment(paymentData);
          
          this.channel.ack(msg);
          console.log('Payment processed successfully');
        } catch (error) {
          console.error('Error processing payment:', error);
          this.channel.ack(msg);
        }
      }
    }, { noAck: false });
  }

  async close() {
    if (this.channel) await this.channel.close();
    if (this.connection) await this.connection.close();
  }
}

const processor = new PaymentProcessor();

processor.connect()
  .then(() => processor.startConsuming())
  .catch(console.error);

process.on('SIGINT', async () => {
  await processor.close();
  process.exit(0);
});